import{_ as r,o as e,c as d,an as a}from"./chunks/framework.CLq1mGhm.js";const c=JSON.parse('{"title":"低成本高性能编码与 Agent 模型调研——对标 DeepSeek V4 Flash","description":"多维比较（SWE-bench / GPQA / AA-Briefcase / Terminal-Bench / 价格）寻找成本低于 DeepSeek V4 Flash 且编码能力相当的模型。结论：严格替代品不存在，但有多维降本选项。","frontmatter":{"title":"低成本高性能编码与 Agent 模型调研——对标 DeepSeek V4 Flash","created":"2026-07-20 13:30","updated":"2026-07-21 17:45","version":"0.3.1","author":"ziogn","tags":["ai","llm","model-comparison","deepseek","qwen","glm","minimax","coding","agent","cost-optimization","research"],"aliases":["比V4 Flash更便宜的模型","V4 Flash 低成本替代调研"],"description":"多维比较（SWE-bench / GPQA / AA-Briefcase / Terminal-Bench / 价格）寻找成本低于 DeepSeek V4 Flash 且编码能力相当的模型。结论：严格替代品不存在，但有多维降本选项。"},"headers":[],"relativePath":"低成本高性能编码与Agent模型调研——对标DeepSeek V4 Flash.md","filePath":"低成本高性能编码与Agent模型调研——对标DeepSeek V4 Flash.md","lastUpdated":null}'),n={name:"低成本高性能编码与Agent模型调研——对标DeepSeek V4 Flash.md"};function o(s,t,l,h,i,g){return e(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="低成本高性能编码与-agent-模型调研——对标-deepseek-v4-flash" tabindex="-1">低成本高性能编码与 Agent 模型调研——对标 DeepSeek V4 Flash <a class="header-anchor" href="#低成本高性能编码与-agent-模型调研——对标-deepseek-v4-flash" aria-label="Permalink to &quot;低成本高性能编码与 Agent 模型调研——对标 DeepSeek V4 Flash&quot;">​</a></h1><hr><h2 id="快查区-快速找到你的答案" tabindex="-1">快查区：快速找到你的答案 <a class="header-anchor" href="#快查区-快速找到你的答案" aria-label="Permalink to &quot;快查区：快速找到你的答案&quot;">​</a></h2><h3 id="一句话定论" tabindex="-1">一句话定论 <a class="header-anchor" href="#一句话定论" aria-label="Permalink to &quot;一句话定论&quot;">​</a></h3><p><strong>别找了，没有比 V4 Flash 更便宜且编码能力不输的 API 模型。</strong></p><p>DeepSeek V4 Flash（输入 ¥1 / 输出 ¥2 / 百万 tokens，SWE-bench <strong>80.6%</strong>）在同价位段没有对手。你的实际选择只有三个方向：</p><table tabindex="0"><thead><tr><th>你的态度</th><th>推荐做法</th><th>代价</th></tr></thead><tbody><tr><td>不能接受能力降级</td><td><strong>继续用 V4 Flash + 优化使用方式</strong></td><td>能力不变，做好缓存命中、错峰使用可大幅降本</td></tr><tr><td>接受小幅降级，想省长期成本</td><td><strong>自部署开源模型</strong>（见 §3）</td><td>SWE-bench 73-77%，需一次性硬件投入</td></tr><tr><td>只做简单任务，越便宜越好</td><td><strong>免费 API 模型</strong>（见 §2）</td><td>能力只有 59.2%，仅适合辅助轮角色</td></tr></tbody></table><p><strong>不想看细节？选第一行即可。</strong> 下面都是为需要详细对比的人准备的。</p><hr><h3 id="本报告怎么读" tabindex="-1">本报告怎么读 <a class="header-anchor" href="#本报告怎么读" aria-label="Permalink to &quot;本报告怎么读&quot;">​</a></h3><table tabindex="0"><thead><tr><th>你的目的</th><th>看哪里</th></tr></thead><tbody><tr><td>只想确认&quot;没有更好的选择&quot;</td><td>看完快查区即可</td></tr><tr><td>想了解哪些模型可以当备胎</td><td>看 <strong>§2</strong></td></tr><tr><td>想算算自部署划不划算</td><td>看 <strong>§3</strong></td></tr><tr><td>需要完整参考</td><td>全看（~20 分钟）</td></tr></tbody></table><hr><h2 id="_1-v4-flash-为什么它是标尺" tabindex="-1">1. V4 Flash：为什么它是标尺 <a class="header-anchor" href="#_1-v4-flash-为什么它是标尺" aria-label="Permalink to &quot;1. V4 Flash：为什么它是标尺&quot;">​</a></h2><p>所有候选模型都归一化到 V4 Flash 这条基线。先把这个标尺看清楚。</p><h3 id="定价与能力" tabindex="-1">定价与能力 <a class="header-anchor" href="#定价与能力" aria-label="Permalink to &quot;定价与能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>数据</th></tr></thead><tbody><tr><td><strong>输入</strong>（缓存未命中）</td><td>¥1 / 百万 tokens</td></tr><tr><td><strong>输入</strong>（缓存命中）</td><td><strong>¥0.02</strong> / 百万 tokens（降幅 98%）</td></tr><tr><td><strong>输出</strong></td><td><strong>¥2</strong> / 百万 tokens（行业门槛价）</td></tr><tr><td><strong>高峰时段</strong>（9-12点、14-18点）</td><td>所有价格翻倍</td></tr><tr><td><strong>上下文</strong></td><td>1M tokens</td></tr><tr><td><strong>架构</strong></td><td>284B 总 / 13B 激活 MoE</td></tr></tbody></table><p><strong>基准能力（多维度）</strong>：</p><table tabindex="0"><thead><tr><th>基准</th><th>分数</th><th>说明</th></tr></thead><tbody><tr><td><strong>SWE-bench Verified</strong></td><td><strong>80.6%</strong></td><td>编码与 bug 修复能力</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>待公开</td><td>终端 Agent 任务（命令执行、环境交互）</td></tr><tr><td><strong>GPQA Diamond</strong></td><td>待公开</td><td>科学推理（物理/化学/生物）；Pro 版为 <strong>90.1%</strong></td></tr><tr><td><strong>AA-Briefcase Elo</strong></td><td>待公开</td><td>智能体长程知识工作</td></tr></tbody></table><p><strong>为什么它能做到这个价格？</strong> V4 Flash 是 284B 参数的 MoE 模型，但每次推理只激活 13B 参数——相当于你有 284B 的&quot;知识储备&quot;，但每次只调用 13B 干活，成本和 13B 小模型差不多。</p><p><strong>定价敏感度</strong>：对编码场景来说，输出价格是第一道门槛。V4 Flash 的输出 ¥2 已经压到行业最低。输出 ¥4 以上的模型，交互式编码场景成本至少翻倍。</p><hr><h3 id="评测维度说明" tabindex="-1">评测维度说明 <a class="header-anchor" href="#评测维度说明" aria-label="Permalink to &quot;评测维度说明&quot;">​</a></h3><p>本文从 <strong>multiple dimensions</strong> 比较模型，不依赖单一基准。各维度对编码场景的意义如下：</p><table tabindex="0"><thead><tr><th>维度</th><th>侧重</th><th>对编码场景的意义</th></tr></thead><tbody><tr><td><strong>SWE-bench Verified</strong></td><td>代码修改与 bug 修复</td><td><strong>核心维度</strong>。模拟 GitHub issue → 修改代码 → 测试通过的端到端流程</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>终端 Agent</td><td>编码 Agent 需要执行命令、操作文件系统、解析输出</td></tr><tr><td><strong>AA-Briefcase Elo</strong></td><td>智能体知识工作</td><td>衡量模型在复杂多步骤工作流中的自主能力</td></tr><tr><td><strong>AA Intelligence Index</strong></td><td>综合智能</td><td>融合 9 项基准（含科学推理、Agent、编码）的综合得分</td></tr><tr><td><strong>GPQA Diamond</strong></td><td>科学推理</td><td>物理/化学/生物专家级问答，反映模型的深层推理能力</td></tr><tr><td><strong>输出速度（tokens/s）</strong></td><td>响应效率</td><td>影响交互式编码的流畅度和 Agent 多步调用总耗时</td></tr><tr><td><strong>价格</strong></td><td>成本</td><td>决定大规模使用的经济可行性</td></tr></tbody></table><blockquote><p><strong>注意</strong>：各基准评测的是不同能力侧面。SWE-bench 分数高的模型在编码场景大概率表现好，但一个有强 Agent 能力但 SWE-bench 稍低的模型，在实际工作流中可能体验更好。<strong>看组合而非单一分数。</strong></p></blockquote><hr><h2 id="_2-比它便宜的模型有哪些" tabindex="-1">2. 比它便宜的模型有哪些 <a class="header-anchor" href="#_2-比它便宜的模型有哪些" aria-label="Permalink to &quot;2. 比它便宜的模型有哪些&quot;">​</a></h2><p><strong>核心结论：没有严格平替。</strong> 下面这些模型在一定条件下可选，但各有取舍。按使用场景分组列出，每个模型只出现一次。</p><hr><h3 id="免费可用-glm-4-7-flash" tabindex="-1">免费可用：GLM-4.7-Flash <a class="header-anchor" href="#免费可用-glm-4-7-flash" aria-label="Permalink to &quot;免费可用：GLM-4.7-Flash&quot;">​</a></h3><ul><li><strong>定价</strong>：完全免费（但只有 1 并发）</li><li><strong>SWE-bench Verified</strong>：<strong>59.2%</strong>（V4 Flash 80.6%）</li><li><strong>GPQA Diamond</strong>：<strong>75.2</strong>（科学推理）</li><li><strong>AA Intelligence Index</strong>：~68（较早版本 v3.x）</li><li><strong>上下文</strong>：200K tokens</li><li><strong>架构</strong>：30B 总 / 3B 激活 MoE</li><li><strong>本地输出速度</strong>：60-80+ tok/s（RTX 3090/4090）</li></ul><p><strong>判断：可用，但只适合&quot;辅助轮&quot;角色。</strong> 免费模型中编码最好的，可以处理 lint 修复、简单补全、代码解释这类轻量任务。但仓库级代码理解和多步骤 Agent 调用场景中，59.2% 意味着成功率远低于 V4 Flash。</p><p><strong>推荐用法</strong>：简单任务走免费，复杂任务切回 V4 Flash。</p><hr><h3 id="同价位可试-mimo-v2-5-standard" tabindex="-1">同价位可试：MiMo V2.5-Standard <a class="header-anchor" href="#同价位可试-mimo-v2-5-standard" aria-label="Permalink to &quot;同价位可试：MiMo V2.5-Standard&quot;">​</a></h3><ul><li><strong>定价</strong>：输出 ¥2（持平 V4 Flash），缓存命中输入 ¥0.02（持平）</li><li><strong>SWE-bench</strong>：不明确（低于 Pro 版）</li><li><strong>AA-Briefcase Elo</strong>：Pro 版 <strong>1581</strong>（开源第一，参考值）</li><li><strong>上下文</strong>：1M tokens</li><li><strong>架构</strong>：1.02T 总 / ~42B 激活 MoE</li><li><strong>多模态</strong>：支持图像/音频/视频（V4 Flash 不支持）</li></ul><p><strong>判断：价格一样但编码能力不确定，可以一试，不建议直接替换主力。</strong> 它是所有候选模型中唯一在纯 API 价格上与 V4 Flash 持平的。如果你的批量处理任务不依赖最高编码能力（如文档生成、国际化翻译），可以分流到 MiMo 来释放 V4 Flash 的并发。</p><hr><h3 id="更便宜但有风险-deepseek-v3-2-中转平台" tabindex="-1">更便宜但有风险：DeepSeek V3.2（中转平台） <a class="header-anchor" href="#更便宜但有风险-deepseek-v3-2-中转平台" aria-label="Permalink to &quot;更便宜但有风险：DeepSeek V3.2（中转平台）&quot;">​</a></h3><p><strong>官方渠道</strong>（输入 ¥2 / 输出 ¥8）：全面不如 V4 Flash，不推荐。</p><p><strong>数眼智能中转平台</strong>（输入 ¥1.2 / 输出 <strong>¥1.8</strong>）：</p><p>这是<strong>唯一输出价格比 V4 Flash（¥2）还低的选项</strong>。但需要注意三点：</p><ol><li>中转平台 SLA、并发、数据安全无官方保障</li><li>128K 上下文只有 V4 Flash（1M）的 1/8，大仓库受限</li><li>编码能力 ~70%（无确切数据），实际可能低于预期</li></ol><p><strong>判断：可作为备选，但风险自担。</strong></p><hr><h3 id="其他仅供参考" tabindex="-1">其他仅供参考 <a class="header-anchor" href="#其他仅供参考" aria-label="Permalink to &quot;其他仅供参考&quot;">​</a></h3><p>这些模型在特定场景下有优势，但编码场景中整体性价比不如 V4 Flash：</p><p><strong>Qwen3.5-Plus</strong>（输入 ¥0.8 / 输出 ¥4.8）：</p><ul><li>输入比 V4 Flash 便宜 20%，但输出贵 140%</li><li>编码场景中输出占成本大头，综合成本远高于 V4 Flash</li><li>缺乏 SWE-bench 数据，编码能力不透明</li><li><strong>GPQA Diamond</strong>：<strong>88.4%</strong>（科学推理能力强）</li></ul><p><strong>Gemini 2.5 Flash-Lite</strong>（~¥0.7 / ~¥2.8）：</p><ul><li>输入价格低，但编码能力推测仅 40-50%（远低于 V4 Flash 的 80.6%）</li><li>需要国际支付 + 国内访问不稳定</li><li>不适合作为中国开发者的编码主力</li></ul><hr><h3 id="全景对比总表" tabindex="-1">全景对比总表 <a class="header-anchor" href="#全景对比总表" aria-label="Permalink to &quot;全景对比总表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>输出¥/M</th><th>SWE-bench</th><th>GPQA</th><th>Terminal-Bench</th><th>上下文</th><th>一句话判断</th></tr></thead><tbody><tr><td><strong>V4 Flash（基准）</strong></td><td><strong>¥2</strong></td><td><strong>80.6%</strong></td><td>—</td><td>—</td><td>1M</td><td>天花板，没有平替</td></tr><tr><td>GLM-4.7-Flash</td><td><strong>¥0</strong></td><td>59.2%</td><td><strong>75.2</strong></td><td>—</td><td>200K</td><td>免费辅助轮</td></tr><tr><td>MiMo V2.5-Std</td><td>¥2</td><td>不明确</td><td>—</td><td>—</td><td>1M</td><td>同价可试</td></tr><tr><td>DeepSeek V3.2（中转）</td><td>¥1.8</td><td>~70%</td><td>—</td><td>—</td><td>128K</td><td>最低价但有风险</td></tr><tr><td>Qwen3.5-Plus</td><td>¥4.8</td><td>无数据</td><td><strong>88.4%</strong></td><td>—</td><td>1M</td><td>输入便宜输出贵</td></tr><tr><td>Gemini 2.5 Flash-Lite</td><td>~¥2.8</td><td>~40-50%</td><td>—</td><td>—</td><td>1M</td><td>不适合编码</td></tr></tbody></table><hr><h2 id="_3-自己部署划算吗" tabindex="-1">3. 自己部署划算吗 <a class="header-anchor" href="#_3-自己部署划算吗" aria-label="Permalink to &quot;3. 自己部署划算吗&quot;">​</a></h2><p>API 找不到更便宜的，但自部署可以——一次性硬件投入，后续调用成本近似为零。</p><hr><h3 id="推荐方案-qwen3-6-35b-a3b" tabindex="-1">推荐方案：Qwen3.6-35B-A3B <a class="header-anchor" href="#推荐方案-qwen3-6-35b-a3b" aria-label="Permalink to &quot;推荐方案：Qwen3.6-35B-A3B&quot;">​</a></h3><p><strong>唯一能在消费级 GPU 上自部署且编码能力接近 V4 Flash 的模型。</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td><strong>73.4%</strong>（差距 7.2 个百分点）</td></tr><tr><td>架构</td><td>35B 总 / <strong>3B 激活</strong> MoE</td></tr><tr><td>上下文</td><td>262K（可扩展至 1M）</td></tr><tr><td>开源协议</td><td>Apache 2.0</td></tr><tr><td>硬件</td><td>RTX 4090 单卡即可（Q4 量化，16-24GB）</td></tr><tr><td>推理速度</td><td>~112 tokens/s</td></tr></tbody></table><h3 id="能力更接近-qwen3-6-27b" tabindex="-1">能力更接近：Qwen3.6-27B <a class="header-anchor" href="#能力更接近-qwen3-6-27b" aria-label="Permalink to &quot;能力更接近：Qwen3.6-27B&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td><strong>77.2%</strong>（差距仅 3.4 个百分点）</td></tr><tr><td>架构</td><td>27B 稠密模型</td></tr><tr><td>硬件需求</td><td>~54GB（FP16），量化后 ~20-28GB</td></tr><tr><td>注意</td><td>单卡 RTX 4090 略吃紧，建议 48GB+ 显存</td></tr></tbody></table><p><strong>如何选择</strong>：</p><ul><li>有 RTX 4090（24GB）→ <strong>35B-A3B</strong>，量化后稳定运行</li><li>有 48GB+ 显存（双卡或专业卡）→ <strong>27B</strong>，能力更接近 V4 Flash</li></ul><h3 id="轻量备选" tabindex="-1">轻量备选 <a class="header-anchor" href="#轻量备选" aria-label="Permalink to &quot;轻量备选&quot;">​</a></h3><ul><li><strong>GLM-4.7-Flash 自部署</strong>（30B/3B MoE，16GB 可运行）：但 API 已免费，自部署价值有限</li><li><strong>Gemma 4-31B</strong>（谷歌开源，31B 稠密）：数学推理极强（AIME 89.2%），但 SWE-bench 无数据，编码能力不确定</li></ul><hr><h3 id="自部署经济性分析" tabindex="-1">自部署经济性分析 <a class="header-anchor" href="#自部署经济性分析" aria-label="Permalink to &quot;自部署经济性分析&quot;">​</a></h3><p><strong>假设</strong>：</p><ul><li>V4 Flash API 综合加权均价约 ¥1.5/百万 tokens</li><li>硬件 RTX 4090（¥15,000）+ 电费 ¥50/月，分 24 个月摊销（¥675/月）</li><li>双卡/Qwen3.6-27B 硬件 ~¥30,000，摊销 ¥1,330/月</li></ul><table tabindex="0"><thead><tr><th>月调用量</th><th>V4 Flash API</th><th>自部署 35B-A3B</th><th>划算吗？</th></tr></thead><tbody><tr><td>100 万 tokens</td><td><strong>¥150/月</strong></td><td>¥675/月（倒挂）</td><td>不划算</td></tr><tr><td>500 万</td><td><strong>¥750/月</strong></td><td>¥675/月（持平）</td><td>可考虑</td></tr><tr><td><strong>1,000 万</strong></td><td><strong>¥1,500/月</strong></td><td>¥675/月（省 55%）</td><td><strong>开始划算</strong></td></tr><tr><td>5,000 万</td><td><strong>¥7,500/月</strong></td><td>¥675/月（省 91%）</td><td>很划算</td></tr><tr><td>1 亿</td><td><strong>¥15,000/月</strong></td><td>¥675/月（省 96%）</td><td>必须自部署</td></tr></tbody></table><p><strong>快速判断</strong>：</p><ul><li><strong>月调用 &lt; 500 万 tokens</strong>：继续用 API，做好缓存命中就够了</li><li><strong>月调用 500-2000 万</strong>：可以算账，半年到两年回本</li><li><strong>月调用 &gt; 2000 万</strong>：强烈推荐自部署</li><li><strong>月调用 &gt; 1 亿</strong>：你不该考虑 API 了</li></ul><blockquote><p>注意：以上未包含自部署的运维成本（模型更新、服务器维护、故障处理）。如果不是 DevOps 熟手，隐性成本可能让实际 ROI 周期翻倍。</p></blockquote><hr><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><h3 id="场景-模型推荐矩阵" tabindex="-1">场景-模型推荐矩阵 <a class="header-anchor" href="#场景-模型推荐矩阵" aria-label="Permalink to &quot;场景-模型推荐矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>使用场景</th><th>首选方案</th><th>月成本（1000 万 tokens）</th></tr></thead><tbody><tr><td>日常交互式编码</td><td>V4 Flash</td><td>¥1,200-1,500</td></tr><tr><td>简单修复/代码补全</td><td>GLM-4.7-Flash（免费）</td><td><strong>¥0</strong></td></tr><tr><td>批量离线处理</td><td>MiMo V2.5-Std 或 V4 Flash</td><td>¥1,000-1,500</td></tr><tr><td>长程 Agent 任务</td><td>V4 Flash / V4 Pro</td><td>¥2,000-4,000</td></tr><tr><td>自部署编码服务器</td><td>Qwen3.6-35B-A3B</td><td>¥675/月（摊销后）</td></tr></tbody></table><h3 id="关联文档" tabindex="-1">关联文档 <a class="header-anchor" href="#关联文档" aria-label="Permalink to &quot;关联文档&quot;">​</a></h3><ul><li><a href="./GSD重度开发模型横评调研报告">GSD 重度开发模型横评调研报告</a> — 本报告的&quot;前传&quot;，横评了多个编码模型的 GSD 适配性</li><li><a href="./deepseek-v4-flash-gsd-core-调研报告">V4 Flash 结合 GSD-Core 工作流调研报告</a> — V4 Flash 在 GSD 三档配置下的实际表现</li><li><a href="./DeepSeek V4 Flash vs MiniMax M3 模型对比分析">DeepSeek V4 Flash vs MiniMax M3 对比分析</a> — 两个模型在编码和 Agent 场景下的详细对比</li></ul><h3 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h3><ol><li><a href="https://blog.csdn.net/aidoudoulong/article/details/159507991" target="_blank" rel="noreferrer">2026 大模型价格与代码能力实测指南</a></li><li><a href="https://blog.csdn.net/dong123dddd/article/details/160454279" target="_blank" rel="noreferrer">2026 国内七大 AI 大模型定价全对比</a></li><li><a href="https://www.cnblogs.com/waluna/p/20188115" target="_blank" rel="noreferrer">MiMo V2.5 全系大幅调价，最高降幅 99%</a></li><li><a href="https://www.cnblogs.com/sing1ee/p/19885253" target="_blank" rel="noreferrer">Qwen3.6-35B-A3B 全面评测</a></li><li><a href="https://www.cnblogs.com/itech/p/19918243" target="_blank" rel="noreferrer">2026 开源五国杀：Qwen3.6、Gemma4、Llama4、GLM-5.1、DeepSeek V4</a></li><li><a href="https://news.qq.com/rain/a/20260523A096IU00" target="_blank" rel="noreferrer">DeepSeek V4-Pro 永久降价至 1/4</a></li><li><a href="https://blog.csdn.net/2201_75517551/article/details/162073007" target="_blank" rel="noreferrer">GLM-5.2 上线，专注 Coding 与长程任务</a></li><li><a href="https://blog.csdn.net/cyf5918/article/details/160377618" target="_blank" rel="noreferrer">DeepSeek V3.2 各渠道价格对比</a></li><li><a href="https://blog.csdn.net/2501_94459390/article/details/160564832" target="_blank" rel="noreferrer">Kimi K2.6 开源，登顶 SWE-Bench Pro</a></li><li><a href="https://blog.csdn.net/cmzznet/article/details/160629524" target="_blank" rel="noreferrer">GLM-5.1 在 Agent 场景性价比拆解</a></li></ol><blockquote><p><strong>数据时效</strong>：以上数据采集于 2026 年 7 月。大模型 API 定价变化极快，使用前请到各模型官网确认最新定价。</p></blockquote><h3 id="变更说明" tabindex="-1">变更说明 <a class="header-anchor" href="#变更说明" aria-label="Permalink to &quot;变更说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>日期</th><th>变更内容</th></tr></thead><tbody><tr><td>v0.3.1</td><td>2026-07-21</td><td>移除 §3（不换模型怎么省钱）。清理导航表和决策表的交叉引用。重编号 §4 → §3。</td></tr><tr><td>v0.3.0</td><td>2026-07-21</td><td>多维度比较升级：引入 AA Intelligence Index / AA-Briefcase Elo / GPQA Diamond / Terminal-Bench 2.0 等基准。新增评测维度说明（§1）。每个模型增加多维数据（GLM-4.7 增加 AA Index &amp; GPQA、MiMo 增加 AA-Briefcase、Qwen3.5-Plus 增加 GPQA）。全景对比表增加 GPQA 和 Terminal-Bench 列。</td></tr><tr><td>v0.2.0</td><td>2026-07-21</td><td>全文重组：9 章压缩为 4 章 + 附录，快查区前置，§3 和 §4 合并，告别重复表述，减少表格数量。数据不变。</td></tr><tr><td>v0.1.0</td><td>2026-07-21</td><td>完成全部 9 章节：核心结论、V4 Flash 基线、候选模型全景对比、低价/免费 API 模型分析、开源自部署方案、混合使用策略、最终选型决策树、关联文档。</td></tr></tbody></table>',86)])])}const p=r(n,[["render",o]]);export{c as __pageData,p as default};
